  1	import React, { FC, useEffect, useState } from 'react';
  2	
  3	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
  4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  5	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
  6	import { Button, Grid } from '@patternfly/react-core';
  7	import { PlusCircleIcon } from '@patternfly/react-icons';
  8	
  9	import { AnnotationsModalRow } from './AnnotationsModalRow';
 10	
 11	import './AnnotationsModal.scss';
 12	
 13	const getIdAnnotations = (annotations: { [key: string]: string }) =>
 14	  Object.fromEntries(Object.entries(annotations).map(([key, value], i) => [i, { key, value }]));
 15	
 16	export const AnnotationsModal: FC<{
 17	  isOpen: boolean;
 18	  obj: K8sResourceCommon;
 19	  onClose: () => void;
 20	  onSubmit: (annotations: { [key: string]: string }) => Promise<K8sResourceCommon | void>;
 21	}> = ({ isOpen, obj, onClose, onSubmit }) => {
 22	  const { t } = useKubevirtTranslation();
 23	
 24	  const [annotations, setAnnotations] = useState<{
 25	    [id: number]: { [key: string]: string };
 26	  }>({});
 27	
 28	  const onAnnotationAdd = () => {
 29	    const keys = new Set([...Object.keys(annotations)]);
 30	    let index = 0;
 31	    while (keys.has(index.toString())) {
 32	      index++;
 33	    }
 34	
 35	    setAnnotations({
 36	      ...annotations,
 37	      [index]: {
 38	        key: '',
 39	        value: '',
 40	      },
 41	    });
 42	  };
 43	
 44	  const onAnnotationsSubmit = () => {
 45	    const uniqWith = (arr, fn) =>
 46	      arr.filter((element, index) => arr.findIndex((step) => fn(element, step)) === index);
 47	
 48	    if (
 49	      uniqWith(Object.values(annotations), (a, b) => a.key === b.key).length !==
 50	      Object.values(annotations).length
 51	    ) {
 52	      return Promise.reject({ message: t('Duplicate keys found') });
 53	    }
 54	
 55	    const updatedAnnotations = Object.fromEntries(
 56	      Object.entries(annotations).map(([, { key, value }]) => [key, value]),
 57	    );
 58	
 59	    return onSubmit(updatedAnnotations);
 60	  };
 61	
 62	  // reset annotations when modal is closed
 63	  useEffect(() => {
 64	    if (obj?.metadata?.annotations) {
 65	      setAnnotations(getIdAnnotations(obj.metadata.annotations));
 66	    }
 67	    // eslint-disable-next-line react-hooks/exhaustive-deps
 68	  }, [isOpen]);
 69	
 70	  return (
 71	    <TabModal<K8sResourceCommon>
 72	      headerText={t('Edit annotations')}
 73	      isOpen={isOpen}
 74	      obj={obj}
 75	      onClose={onClose}
 76	      onSubmit={onAnnotationsSubmit}
 77	    >
 78	      <Grid hasGutter>
 79	        {Object.entries(annotations || {}).map(([id, { key, value }]) => (
 80	          <AnnotationsModalRow
 81	            onChange={(annotation) =>
 82	              setAnnotations({
 83	                ...annotations,
 84	                [id]: annotation,
 85	              })
 86	            }
 87	            onDelete={() =>
 88	              setAnnotations(
 89	                Object.fromEntries(Object.entries(annotations).filter(([k]) => k !== id)),
 90	              )
 91	            }
 92	            annotation={{ key, value }}
 93	            key={id}
 94	          />
 95	        ))}
 96	        <div className="co-toolbar__group co-toolbar__group--left">
 97	          <Button
 98	            className="pf-m-link--align-left"
 99	            icon={<PlusCircleIcon />}
100	            onClick={() => onAnnotationAdd()}
101	            size="sm"
102	            variant="link"
103	          >
104	            {t('Add more')}
105	          </Button>
106	        </div>
107	      </Grid>
108	    </TabModal>
109	  );
110	};

